import network
import socket
import struct
import hashlib
import binascii
import json
import time
import gc

class WebSocketServer:
    def __init__(self, port=80):
        self.port = port
        self.server_socket = None
        self.clients = []
        self.running = False
        
    def start(self):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_socket.bind(('', self.port))
        self.server_socket.listen(5)
        self.server_socket.setblocking(False)
        self.running = True
        print(f"WebSocket server started on port {self.port}")
        
    def stop(self):
        self.running = False
        for client in self.clients:
            try:
                client.close()
            except:
                pass
        self.clients = []
        if self.server_socket:
            self.server_socket.close()
        print("WebSocket server stopped")
        
    def _generate_accept_key(self, key):
        magic = b'258EAFA5-E914-47DA-95CA-C5AB0DC85B11'
        sha1 = hashlib.sha1(key.encode() + magic)
        return binascii.b2a_base64(sha1.digest()).strip()
        
    def _handshake(self, client):
        try:
            request = client.recv(1024).decode('utf-8')
            lines = request.split('\r\n')
            
            key = None
            for line in lines:
                if line.startswith('Sec-WebSocket-Key:'):
                    key = line.split(': ')[1]
                    break
                    
            if not key:
                return False
                
            accept_key = self._generate_accept_key(key)
            
            response = (
                'HTTP/1.1 101 Switching Protocols\r\n'
                'Upgrade: websocket\r\n'
                'Connection: Upgrade\r\n'
                f'Sec-WebSocket-Accept: {accept_key.decode()}\r\n'
                '\r\n'
            )
            
            client.send(response.encode())
            return True
        except Exception as e:
            print(f"Handshake error: {e}")
            return False
            
    def _decode_frame(self, data):
        if len(data) < 2:
            return None
            
        byte1 = data[0]
        byte2 = data[1]
        
        fin = (byte1 >> 7) & 1
        opcode = byte1 & 0x0F
        masked = (byte2 >> 7) & 1
        payload_length = byte2 & 0x7F
        
        offset = 2
        
        if payload_length == 126:
            if len(data) < 4:
                return None
            payload_length = struct.unpack('>H', data[2:4])[0]
            offset = 4
        elif payload_length == 127:
            if len(data) < 10:
                return None
            payload_length = struct.unpack('>Q', data[2:10])[0]
            offset = 10
            
        if masked:
            if len(data) < offset + 4:
                return None
            masking_key = data[offset:offset+4]
            offset += 4
        else:
            masking_key = None
            
        if len(data) < offset + payload_length:
            return None
            
        payload = bytearray(data[offset:offset+payload_length])
        
        if masked and masking_key:
            for i in range(len(payload)):
                payload[i] ^= masking_key[i % 4]
                
        if opcode == 0x8:
            return {'type': 'close'}
        elif opcode == 0x9:
            return {'type': 'ping', 'data': payload}
        elif opcode == 0x1:
            return {'type': 'text', 'data': payload.decode('utf-8')}
        elif opcode == 0x2:
            return {'type': 'binary', 'data': bytes(payload)}
            
        return None
        
    def _encode_frame(self, data, opcode=0x1):
        if isinstance(data, str):
            data = data.encode('utf-8')
            
        frame = bytearray()
        frame.append(0x80 | opcode)
        
        length = len(data)
        if length < 126:
            frame.append(length)
        elif length < 65536:
            frame.append(126)
            frame.extend(struct.pack('>H', length))
        else:
            frame.append(127)
            frame.extend(struct.pack('>Q', length))
            
        frame.extend(data)
        return bytes(frame)
        
    def send_message(self, client, message):
        try:
            if isinstance(message, dict):
                message = json.dumps(message)
            frame = self._encode_frame(message)
            client.send(frame)
            return True
        except Exception as e:
            print(f"Send error: {e}")
            return False
            
    def broadcast(self, message):
        dead_clients = []
        for client in self.clients:
            if not self.send_message(client, message):
                dead_clients.append(client)
                
        for client in dead_clients:
            self.clients.remove(client)
            try:
                client.close()
            except:
                pass
                
    def handle_command(self, command_data):
        try:
            command = json.loads(command_data)
            action = command.get('action', '')
            
            if action == 'turn_on':
                print("Action: Turn ON")
                return {'status': 'success', 'action': 'turn_on', 'message': 'Device turned on'}
            elif action == 'turn_off':
                print("Action: Turn OFF")
                return {'status': 'success', 'action': 'turn_off', 'message': 'Device turned off'}
            elif action == 'get_status':
                print("Action: Get Status")
                return {'status': 'success', 'action': 'get_status', 'state': 'online', 'uptime': time.time()}
            elif action == 'set_value':
                value = command.get('value', 0)
                print(f"Action: Set Value to {value}")
                return {'status': 'success', 'action': 'set_value', 'value': value}
            else:
                return {'status': 'error', 'message': f'Unknown action: {action}'}
        except Exception as e:
            print(f"Command handling error: {e}")
            return {'status': 'error', 'message': str(e)}
            
    def process(self):
        try:
            client_socket, addr = self.server_socket.accept()
            client_socket.setblocking(False)
            print(f"New connection from {addr}")
            
            if self._handshake(client_socket):
                self.clients.append(client_socket)
                print(f"WebSocket connection established with {addr}")
                self.send_message(client_socket, {'status': 'connected', 'message': 'Welcome to ESP32 WebSocket Server'})
            else:
                client_socket.close()
        except OSError:
            pass
            
        dead_clients = []
        for client in self.clients:
            try:
                data = client.recv(1024)
                if not data:
                    dead_clients.append(client)
                    continue
                    
                frame = self._decode_frame(data)
                if frame:
                    if frame['type'] == 'close':
                        dead_clients.append(client)
                    elif frame['type'] == 'ping':
                        pong = self._encode_frame(frame['data'], 0xA)
                        client.send(pong)
                    elif frame['type'] == 'text':
                        print(f"Received: {frame['data']}")
                        response = self.handle_command(frame['data'])
                        self.send_message(client, response)
                        
            except OSError:
                pass
            except Exception as e:
                print(f"Client error: {e}")
                dead_clients.append(client)
                
        for client in dead_clients:
            if client in self.clients:
                self.clients.remove(client)
            try:
                client.close()
            except:
                pass
                
        gc.collect()


def connect_wifi(ssid, password):
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    
    if not wlan.isconnected():
        print(f'Connecting to {ssid}...')
        wlan.connect(ssid, password)
        
        timeout = 10
        while not wlan.isconnected() and timeout > 0:
            time.sleep(1)
            timeout -= 1
            
    if wlan.isconnected():
        print('Network connected!')
        print('IP address:', wlan.ifconfig()[0])
        return wlan.ifconfig()[0]
    else:
        print('Failed to connect to WiFi')
        return None


def main():
    WIFI_SSID = 'YOUR_WIFI_SSID'
    WIFI_PASSWORD = 'YOUR_WIFI_PASSWORD'
    
    ip = connect_wifi(WIFI_SSID, WIFI_PASSWORD)
    
    if ip:
        ws_server = WebSocketServer(port=80)
        ws_server.start()
        
        print(f"WebSocket server running at ws://{ip}:80")
        print("Waiting for connections...")
        
        try:
            while True:
                ws_server.process()
                time.sleep(0.01)
        except KeyboardInterrupt:
            print("\nShutting down...")
            ws_server.stop()


if __name__ == '__main__':
    main()